import React, { useState, useEffect } from 'react';

const App = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [filters, setFilters] = useState({});
  const [products, setProducts] = useState([]);
  const [pricing, setPricing] = useState({});

  useEffect(() => {
    // Fetch products and pricing data
    fetch('/api/products')
      .then(response => response.json())
      .then(data => setProducts(data));
  }, []);

  const handleSearch = (event) => {
    setSearchQuery(event.target.value);
  };

  const handleFilterChange = (event) => {
    setFilters(event.target.value);
  };

  const handlePricingChange = (event) => {
    setPricing(event.target.value);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-full max-w-md mx-auto p-4 bg-white shadow-md rounded-md">
        <div className="flex items-center justify-between mb-4">
          <input
            type='search'
            placeholder='Search'
            value={searchQuery}
            onChange={handleSearch}
            className="w-full py-2 pl-10 text-sm text-gray-700 focus:outline-none focus:ring-2 focus:ring-gray-600 focus:border-transparent"
          />
          <button
            className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-700 focus:border-transparent">
            Search
          </button>
        </div>
        <div className="flex flex-wrap -mx-4">
          {Object.keys(filters).map((filterKey) => (
            <div
              key={filterKey}
              className="w-full md:w-1/2 xl:w-1/3 p-4 mb-4">
              <input
                type='checkbox'
                id={filterKey}
                value={filters[filterKey]}
                onChange={handleFilterChange}
                className="mr-2 text-blue-500"
              />
              <label
                className="text-gray-600 text-sm"
                htmlFor={filterKey}
              >
                {filterKey.charAt(0).toUpperCase() + filterKey.slice(1)}
              </label>
            </div>
          ))}
        </div>
        <div className="mt-4 mb-4">
          <h2 className="text-gray-800 text-lg">
            Pricing:
          </h2>
          <ul className="list-disc ml-4 text-gray-600">
            <li>
              <input
                type='range'
                id='price-range'
                value={pricing['price-range']}
                onChange={handlePricingChange}
                className="w-full h-2 text-gray-500 focus:outline-none focus:ring-2 focus:ring-gray-600 focus:border-transparent"
              />
              <span className="absolute -left-2 text-gray-500">$</span>
              <span className="absolute -right-2 text-gray-500">$</span>
            </li>
          </ul>
        </div>
        <div className="flex flex-wrap -mx-4">
          {products.map((product) => (
            <div
              key={product.id}
              className="w-full md:w-1/2 xl:w-1/3 p-4 mb-4">
              <div className="bg-white rounded-md shadow-md p-4">
                <h3 className="text-gray-800 text-lg">
                  {product.name}
                </h3>
                <p className="text-gray-600 text-sm">
                  {product.description}
                </p>
                <p className="text-gray-600 text-sm">
                  Price: ${product.price}
                </p>
                <button
                  className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-700 focus:border-transparent">
                  Add to Cart
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default App;
